import (
	"container/heap"
)

type State struct {
	cost int64
	i    int
	j    int
	p    int // 0 for even, 1 for odd
}

type PriorityQueue []*State

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*State)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(m int64, n int64, waitCost [][]int64) int64 {
	mInt := int(m)
	nInt := int(n)
	if mInt == 0 || nInt == 0 {
		return 0
	}

	// Initialize distance array
	dist := make([][][]int64, mInt)
	for i := 0; i < mInt; i++ {
		dist[i] = make([][]int64, nInt)
		for j := 0; j < nInt; j++ {
			dist[i][j] = make([]int64, 2)
			for k := 0; k < 2; k++ {
				dist[i][j][k] = 1 << 63 - 1 // Initialize to infinity
			}
		}
	}

	// Initial state: (0,0), parity 1 (odd), cost is entry cost (0+1)*(0+1) = 1
	dist[0][0][1] = 1

	// Priority queue
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	initial := &State{cost: 1, i: 0, j: 0, p: 1}
	heap.Push(&pq, initial)

	// Directions for moving: right (0,1) and down (1,0)
	directions := [][2]int{{0, 1}, {1, 0}}

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*State)
		cost := current.cost
		i := current.i
		j := current.j
		p := current.p

		// Check if we have reached the destination
		if i == mInt-1 && j == nInt-1 {
			return cost
		}

		// Process transitions based on parity
		if p == 1 { // odd: move
			// Try moving right
			ni, nj := i, j+1
			if nj < nInt {
				newCost := cost + int64((ni+1)*(nj+1))
				if newCost < dist[ni][nj][0] {
					dist[ni][nj][0] = newCost
					heap.Push(&pq, &State{cost: newCost, i: ni, j: nj, p: 0})
				}
			}
			// Try moving down
			ni, nj := i+1, j
			if ni < mInt {
				newCost := cost + int64((ni+1)*(nj+1))
				if newCost < dist[ni][nj][0] {
					dist[ni][nj][0] = newCost
					heap.Push(&pq, &State{cost: newCost, i: ni, j: nj, p: 0})
				}
			}
		} else { // even: wait
			// Wait at current cell, new parity is 1
			newCost := cost + int64(waitCost[i][j])
			if newCost < dist[i][j][1] {
				dist[i][j][1] = newCost
				heap.Push(&pq, &State{cost: newCost, i: i, j: j, p: 1})
			}
		}
	}

	// If we exit the loop without returning, it's impossible (but the problem says there's a path)
	return -1
}
